    </svg></div></div><div class="code-content"><div class="code-block dsa_article_code_active" data-lang="cpp"><div class="line-numbers line-num"><span>1</span><span>2</span><span>3</span><span>4</span><span>5</span><span>6</span><span>7</span><span>8</span><span>9</span><span>10</span><span>11</span><span>12</span><span>13</span><span>14</span><span>15</span><span>16</span><span>17</span><span>18</span><span>19</span><span>20</span><span>21</span><span>22</span><span>23</span><span>24</span><span>25</span><span>26</span><span>27</span><span>28</span><span>29</span><span>30</span><span>31</span><span>32</span><span>33</span><span>34</span><span>35</span><span>36</span><span>37</span><span>38</span><span>39</span><span>40</span><span>41</span><span>42</span><span>43</span></div><pre class="wp-block-code"><code lang="cpp" class="language-cpp">#include &lt;bits/stdc++.h&gt;
using namespace std;

// Definition of a singly-linked list node
struct ListNode {
    int val;              
    ListNode* next;       
    ListNode(int x) : val(x), next(NULL) {}
};

class Solution {
public:
    // Function to delete a given node (not the tail node)
    void deleteNode(ListNode* node) {
        // Copy the value from the next node into the current node
        node-&gt;val = node-&gt;next-&gt;val;

        // Bypass the next node (unlink it from the list)
        node-&gt;next = node-&gt;next-&gt;next;
    }
};

// Driver code
int main() {
    // Create a linked list: 4 -&gt; 5 -&gt; 1 -&gt; 9
    ListNode* head = new ListNode(4);
    head-&gt;next = new ListNode(5);
    head-&gt;next-&gt;next = new ListNode(1);
    head-&gt;next-&gt;next-&gt;next = new ListNode(9);

    // Suppose we want to delete node with value 5
    Solution sol;
    sol.deleteNode(head-&gt;next);  

    // Print updated list: expected output is 4 -&gt; 1 -&gt; 9
    ListNode* curr = head;
    while (curr) {
        cout &lt;&lt; curr-&gt;val &lt;&lt; " ";
        curr = curr-&gt;next;
    }
    return 0;
}
</code></pre></div><div class="code-block" data-lang="java"><div class="line-numbers line-num"><span>1</span><span>2</span><span>3</span><span>4</span><span>5</span><span>6</span><span>7</span><span>8</span><span>9</span><span>10</span><span>11</span><span>12</span><span>13</span><span>14</span><span>15</span><span>16</span><span>17</span><span>18</span><span>19</span><span>20</span><span>21</span><span>22</span><span>23</span><span>24</span><span>25</span><span>26</span><span>27</span><span>28</span><span>29</span><span>30</span><span>31</span><span>32</span><span>33</span><span>34</span><span>35</span><span>36</span><span>37</span><span>38</span><span>39</span></div><pre class="wp-block-code"><code lang="java" class="language-java">// Definition for singly-linked list
class ListNode {
    int val;           
    ListNode next;    
    ListNode(int x) { val = x; }
}

class Solution {
    // Function to delete a given node (not the tail)
    public void deleteNode(ListNode node) {
        // Copy value of next node into current node
        node.val = node.next.val;

        // Bypass the next node
        node.next = node.next.next;
    }
}

public class Main {
    public static void main(String[] args) {
        // Create a linked list: 4 -&gt; 5 -&gt; 1 -&gt; 9
        ListNode head = new ListNode(4);
        head.next = new ListNode(5);
        head.next.next = new ListNode(1);
        head.next.next.next = new ListNode(9);

        // Delete node with value 5
        Solution sol = new Solution();
        sol.deleteNode(head.next);

        // Print updated list: expected output 4 -&gt; 1 -&gt; 9
        ListNode curr = head;
        while (curr != null) {
            System.out.print(curr.val + " ");
            curr = curr.next;
        }
    }
}
