</code></pre></div><div class="code-block" data-lang="javascript"><div class="line-numbers line-num"><span>1</span><span>2</span><span>3</span><span>4</span><span>5</span><span>6</span><span>7</span><span>8</span><span>9</span><span>10</span><span>11</span><span>12</span><span>13</span><span>14</span><span>15</span><span>16</span><span>17</span><span>18</span><span>19</span><span>20</span><span>21</span><span>22</span><span>23</span><span>24</span><span>25</span><span>26</span><span>27</span><span>28</span><span>29</span><span>30</span><span>31</span><span>32</span><span>33</span><span>34</span><span>35</span><span>36</span><span>37</span><span>38</span><span>39</span><span>40</span><span>41</span><span>42</span><span>43</span></div><pre class="wp-block-code"><code lang="javascript" class="language-javascript">// Definition for singly-linked list node
class ListNode {
    constructor(val, next = null) {
        this.val = val;   
        this.next = next; 
    }
}

class Solution {
    // Function to delete a given node (not the tail)
    deleteNode(node) {
        // Copy the next node's value into the current node
        node.val = node.next.val;

        // Bypass the next node
        node.next = node.next.next;
    }
}

// Driver code
function main() {
    // Create linked list: 4 -&gt; 5 -&gt; 1 -&gt; 9
    let head = new ListNode(4);
    head.next = new ListNode(5);
    head.next.next = new ListNode(1);
    head.next.next.next = new ListNode(9);

    // Delete node with value 5
    let sol = new Solution();
    sol.deleteNode(head.next);

    // Print updated list: expected 4 -&gt; 1 -&gt; 9
    let curr = head;
    let result = "";
    while (curr) {
        result += curr.val + " ";
        curr = curr.next;
    }
    console.log(result);
}

main();
